const VI_DIACRITIC = /[àáạảãâầấậẩẫăằắặẳẵèéẹẻẽêềếệểễìíịỉĩòóọỏõôồốộổỗơờớợởỡùúụủũưừứựửữỳýỵỷỹđ]/i;

const ROLE_STOCK_QUERY = {
  hook: 'Vietnamese young couple phone apartment surprised',
  tension: 'worried person mortgage paperwork desk close up',
  value: 'Vietnam apartment living room interior family',
  proof: 'calculator bank documents desk flat lay no people',
  checklist: 'checklist document pen phone desk no people',
  cta: 'Vietnam city skyline apartment sunset portrait',
  brand_outro: 'Vietnam warm sunset apartment keys handover portrait',
};

function looksVietnamese(text) {
  return VI_DIACRITIC.test(String(text || ''));
}

function sanitizeEnglishStockQuery(raw) {
  return String(raw || '')
    .replace(/[^\x20-\x7E]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 80);
}

function isEnglishStockQuery(raw) {
  const rawStr = String(raw || '').trim();
  if (rawStr.length < 5) return false;
  if (looksVietnamese(rawStr)) return false;

  const q = sanitizeEnglishStockQuery(rawStr);
  if (q.length < 5) return false;
  if (q.length < rawStr.length * 0.85) return false;

  const letters = q.match(/[a-zA-Z]/g) || [];
  const alnum = q.replace(/\s/g, '');
  if (!alnum.length) return false;
  return letters.length / alnum.length >= 0.65;
}

function parseBeatsJson(raw) {
  if (!raw) return [];
  try {
    const beats = typeof raw === 'string' ? JSON.parse(raw) : raw;
    return Array.isArray(beats) ? beats : [];
  } catch {
    return [];
  }
}

function validateBeatsRenderSpec(beats) {
  const errors = [];
  if (!Array.isArray(beats) || beats.length < 4) {
    return {
      ok: false,
      errors: [{ code: 'INSUFFICIENT_BEATS', hint: 'Cần ≥4 beats — re-run Agent 6 v3' }],
      production_brief_version: null,
    };
  }

  let versionHint = null;
  for (let i = 0; i < beats.length; i += 1) {
    const b = beats[i] || {};
    const spec = b.visual_spec && typeof b.visual_spec === 'object' ? b.visual_spec : null;
    const type = String(spec?.type || 'broll').toLowerCase();

    if (!spec) {
      errors.push({
        beat_index: i,
        role: b.role || null,
        code: 'MISSING_VISUAL_SPEC',
        hint: 'Beat thiếu visual_spec — Agent 6 phải production_brief_version: 3',
      });
      versionHint = versionHint || 'legacy';
      continue;
    }

    if (type !== 'broll') continue;

    const sq = String(spec.stock_query || '').trim();
    if (!sq || sq.length < 5) {
      errors.push({
        beat_index: i,
        role: b.role || null,
        code: 'MISSING_STOCK_QUERY',
        hint: 'visual_spec.stock_query bắt buộc (English, ≤80 chars)',
      });
      continue;
    }
    if (!isEnglishStockQuery(sq)) {
      errors.push({
        beat_index: i,
        role: b.role || null,
        code: 'STOCK_QUERY_NOT_ENGLISH',
        stock_query_preview: sq.slice(0, 60),
        hint: 'stock_query phải tiếng Anh — không dùng mô tả visual tiếng Việt',
      });
    }
  }

  return {
    ok: errors.length === 0,
    errors,
    beat_count: beats.length,
    production_brief_version: versionHint === 'legacy' ? '<3' : errors.length ? 'invalid' : '3',
  };
}

function roleFallbackQuery(beat, segment) {
  const role = String(beat?.role || 'value').toLowerCase();
  const base = ROLE_STOCK_QUERY[role] || ROLE_STOCK_QUERY.value;
  const segKey = String(segment || '').toLowerCase();
  if (role === 'hook' && segKey === 'noxh_income') {
    return 'Vietnam social housing young family apartment keys'.slice(0, 80);
  }
  if (role === 'hook' && segKey === 'sme_credit') {
    return 'Vietnamese small business owner bank office'.slice(0, 80);
  }
  return base.slice(0, 80);
}

function resolvePexelsStockQuery(beat, segment) {
  const spec = beat?.visual_spec || {};
  const type = String(spec.type || 'broll').toLowerCase();
  if (type !== 'broll') return null;

  const sq = sanitizeEnglishStockQuery(spec.stock_query);
  if (!isEnglishStockQuery(sq)) return null;

  const lower = sq.toLowerCase();
  const hasVn = lower.includes('vietnam') || lower.includes('vietnamese') || lower.includes('southeast asian');
  const segKey = String(segment || '').toLowerCase();
  const preferVn = segKey === 'noxh_income' || segKey === 'valuation' || segKey === 'sme_credit';
  const noPeople = lower.includes('no people') || lower.includes('no person');

  if (preferVn && !hasVn && !noPeople) {
    return `Vietnamese ${sq}`.slice(0, 80);
  }
  return sq;
}

const BATCH = 1;

const DONE_RENDER = new Set(['rendering', 'ready_for_review', 'published']);

function parseMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

function truthyL3(v) {
  if (v === true || v === 1) return true;
  const s = String(v || '').trim().toLowerCase();
  return s === 'true' || s === '1' || s === 'yes';
}

const data = $getWorkflowStaticData('global');
if (!data.a7_stats) data.a7_stats = {};

const res = $input.first().json;
if (res?.error?.message || (res?.code && res.code >= 400)) {
  data.a7_stats.fetch_error = String(res.error?.message || res.message || res.code).slice(0, 300);
  return [{
    json: {
      empty: true,
      message: 'Fetch video_drafts lỗi — gán credential googleApi trên node Fetch',
      fetch_error: data.a7_stats.fetch_error,
    },
  }];
}

const rows = Array.isArray(res.values) ? res.values : [];
if (rows.length < 2) {
  data.a7_stats.no_candidates = true;
  data.a7_stats.candidate_count = 0;
  return [{ json: { empty: true, message: 'video_drafts trống hoặc Fetch không trả values' } }];
}

const headers = rows[0].map((x) => String(x || '').trim().toLowerCase());
const idx = (name) => headers.indexOf(name);

const col = {
  key: idx('source_normalized_key'),
  platform: idx('platform'),
  segment: idx('segment'),
  title: idx('title'),
  hook: idx('hook_3s'),
  spoken: idx('spoken_script'),
  beats: idx('beats_json'),
  onScreen: idx('on_screen_text'),
  caption: idx('caption'),
  cta: idx('cta_keyword'),
  duration: idx('duration_sec'),
  aspect: idx('aspect_ratio'),
  status: idx('status'),
  l3: idx('l3_approved'),
  meta: idx('meta'),
};

const candidates = [];
const nearMiss = [];

for (let r = 1; r < rows.length; r += 1) {
  const row = rows[r];
  if (!row?.some((c) => String(c || '').trim())) continue;

  const status = String(row[col.status] || '').trim().toLowerCase();
  const l3ok = truthyL3(row[col.l3]);
  const meta = parseMeta(row[col.meta]);
  const renderStatus = String(meta.render_status || '').trim().toLowerCase();
  const title = String(row[col.title] || '').slice(0, 40);
  const sheetRow = r + 1;

  if (status !== 'approved') {
    if (l3ok || status === 'ready_for_review' || meta.render_url) {
      nearMiss.push({ row: sheetRow, reason: `status=${status || '(trống)'} (cần approved)`, title, render_url: meta.render_url || null });
    }
    continue;
  }
  if (!l3ok) {
    nearMiss.push({ row: sheetRow, reason: 'l3_approved chưa tick', title });
    continue;
  }
  if (DONE_RENDER.has(renderStatus)) {
    nearMiss.push({ row: sheetRow, reason: `meta.render_status=${renderStatus} (đã render)`, title, render_url: meta.render_url || null });
    continue;
  }

  candidates.push({
    sheet_row: r + 1,
    source_normalized_key: String(row[col.key] || ''),
    platform: String(row[col.platform] || 'tiktok'),
    segment: String(row[col.segment] || 'general_inbound'),
    title: String(row[col.title] || ''),
    hook_3s: String(row[col.hook] || ''),
    spoken_script: String(row[col.spoken] || ''),
    beats_json: String(row[col.beats] || '[]'),
    on_screen_text: String(row[col.onScreen] || ''),
    caption: String(row[col.caption] || ''),
    cta_keyword: String(row[col.cta] || ''),
    duration_sec: Number(row[col.duration] || 30) || 30,
    aspect_ratio: String(row[col.aspect] || '9:16'),
    meta,
  });
}

const eligible = [];
for (const c of candidates) {
  const beats = parseBeatsJson(c.beats_json);
  const spec = validateBeatsRenderSpec(beats);
  if (spec.ok) {
    eligible.push(c);
    continue;
  }
  const first = spec.errors[0] || {};
  nearMiss.push({
    row: c.sheet_row,
    reason: `beats v3 invalid: ${first.code || 'INVALID_RENDER_SPEC'}`,
    title: String(c.title || '').slice(0, 40),
    hint: first.hint || 'Re-run Agent 6 production_brief_version 3',
  });
}

candidates.length = 0;
candidates.push(...eligible);

candidates.sort((a, b) => a.sheet_row - b.sheet_row);
const batch = candidates.slice(0, BATCH);

data.a7_stats.candidate_count = candidates.length;
data.a7_stats.batch_count = batch.length;

if (!batch.length) {
  data.a7_stats.no_candidates = true;
  data.a7_stats.near_miss = nearMiss.slice(0, 5);
  if (nearMiss.length) {
    const first = nearMiss[0];
    const extra = first.hint ? ` — ${first.hint}` : '';
    data.a7_stats.skip_hint = `Row ${first.row}: ${first.reason}${extra}${first.render_url ? ' — đã có render_url' : ''}`;
  }
  return [{
    json: {
      empty: true,
      message: 'Không còn video_drafts approved + l3 + beats v3 (stock_query EN) chưa render',
      pending_total: candidates.length,
      near_miss: nearMiss.slice(0, 5),
      skip_hint: data.a7_stats.skip_hint || null,
    },
  }];
}

data.a7_stats.no_candidates = false;
return batch.map((c) => ({ json: { ...c, empty: false } }));

const data = $getWorkflowStaticData('global');
data.a7_stats = { render_ok: 0, render_fail: 0, payload_fail: 0, sheet_fail: 0, no_candidates: false };
data.a7_poll = {};
return $input.all();

const data = $getWorkflowStaticData('global');
if (!data.a7_stats) data.a7_stats = {};

const blockEnv = String($env.N8N_BLOCK_ENV_ACCESS_IN_NODE ?? '');
const pexels = $env.PEXELS_API_KEY || '';

data.a7_env = {
  render_engine: 'creatomate_renderscript_v2',
  has_pexels_key: pexels.length > 8,
  has_tts_url: String($env.MAGNIX_VIDEO_TTS_URL || '').length > 8,
  has_webhook_token: String($env.MAGNIX_WEBHOOK_TOKEN || '').length > 8,
  block_env_access: blockEnv,
  env_blocked: blockEnv === 'true',
  auth_note: 'Creatomate API key qua Header Auth credential trên HTTP POST',
